26	YOSYS_NAMESPACE_BEGIN
27	
28	struct CellType
29	{
30		RTLIL::IdString type;
31		pool<RTLIL::IdString> inputs, outputs;
32		bool is_evaluable;
33		bool is_combinatorial;
34		bool is_synthesizable;
35	};
36	
37	struct CellTypes
38	{
39		dict<RTLIL::IdString, CellType> cell_types;
40	
41		CellTypes()
42		{
43		}
44	
45		CellTypes(RTLIL::Design *design)
46		{
47			setup(design);
48		}
49	
50		void setup(RTLIL::Design *design = NULL)
51		{
52			if (design)
53				setup_design(design);
54	
55			setup_internals();
56			setup_internals_mem();
57			setup_internals_anyinit();
58			setup_stdcells();
59			setup_stdcells_mem();
60		}
61	
62		void setup_type(RTLIL::IdString type, const pool<RTLIL::IdString> &inputs, const pool<RTLIL::IdString> &outputs, bool is_evaluable = false, bool is_combinatorial = false, bool is_synthesizable = false)
63		{
64			CellType ct = {type, inputs, outputs, is_evaluable, is_combinatorial, is_synthesizable};
65			cell_types[ct.type] = ct;
66		}
67	
68		void setup_module(RTLIL::Module *module)
69		{
70			pool<RTLIL::IdString> inputs, outputs;
71			for (RTLIL::IdString wire_name : module->ports) {
72				RTLIL::Wire *wire = module->wire(wire_name);
73				if (wire->port_input)
74					inputs.insert(wire->name);
75				if (wire->port_output)
76					outputs.insert(wire->name);
77			}
78			setup_type(module->name, inputs, outputs);
79		}
80	
81		void setup_design(RTLIL::Design *design)
82		{
83			for (auto module : design->modules())
84				setup_module(module);
85		}
