119		void setup_internals_eval()
120		{
121			std::vector<RTLIL::IdString> unary_ops = {
122				ID($not), ID($pos), ID($buf), ID($neg),
123				ID($reduce_and), ID($reduce_or), ID($reduce_xor), ID($reduce_xnor), ID($reduce_bool),
124				ID($logic_not), ID($slice), ID($lut), ID($sop)
125			};
126	
127			std::vector<RTLIL::IdString> binary_ops = {
128				ID($and), ID($or), ID($xor), ID($xnor),
129				ID($shl), ID($shr), ID($sshl), ID($sshr), ID($shift), ID($shiftx),
130				ID($lt), ID($le), ID($eq), ID($ne), ID($eqx), ID($nex), ID($ge), ID($gt),
131				ID($add), ID($sub), ID($mul), ID($div), ID($mod), ID($divfloor), ID($modfloor), ID($pow),
132				ID($logic_and), ID($logic_or), ID($concat), ID($macc),
133				ID($bweqx)
134			};
135	
136			for (auto type : unary_ops)
137				setup_type(type, {ID::A}, {ID::Y}, true);
138	
139			for (auto type : binary_ops)
140				setup_type(type, {ID::A, ID::B}, {ID::Y}, true);
141	
142			for (auto type : std::vector<RTLIL::IdString>({ID($mux), ID($pmux), ID($bwmux)}))
143				setup_type(type, {ID::A, ID::B, ID::S}, {ID::Y}, true);
144	
145			for (auto type : std::vector<RTLIL::IdString>({ID($bmux), ID($demux)}))
146				setup_type(type, {ID::A, ID::S}, {ID::Y}, true);
147	
148			setup_type(ID($lcu), {ID::P, ID::G, ID::CI}, {ID::CO}, true);
149			setup_type(ID($alu), {ID::A, ID::B, ID::CI, ID::BI}, {ID::X, ID::Y, ID::CO}, true);
150			setup_type(ID($macc_v2), {ID::A, ID::B, ID::C}, {ID::Y}, true);
151			setup_type(ID($fa), {ID::A, ID::B, ID::C}, {ID::X, ID::Y}, true);
152		}
