326		RTLIL::PortDir cell_port_dir(RTLIL::IdString type, RTLIL::IdString port) const
327		{
328			auto it = cell_types.find(type);
329			if (it == cell_types.end())
330				return RTLIL::PD_UNKNOWN;
331			bool is_input = it->second.inputs.count(port);
332			bool is_output = it->second.outputs.count(port);
333			return RTLIL::PortDir(is_input + is_output * 2);
334		}
