342		static RTLIL::Const eval_not(RTLIL::Const v)
343		{
344			for (auto bit : v)
345				if (bit == State::S0) bit = State::S1;
346				else if (bit == State::S1) bit = State::S0;
347			return v;
348		}
349	
350		// Consider using the ConstEval struct instead if you need named ports and/or multiple outputs
351		static RTLIL::Const eval(RTLIL::IdString type, const RTLIL::Const &arg1, const RTLIL::Const &arg2, bool signed1, bool signed2, int result_len, bool *errp = nullptr)
352		{
353			if (type == ID($sshr) && !signed1)
354				type = ID($shr);
355			if (type == ID($sshl) && !signed1)
356				type = ID($shl);
357	
358			if (type != ID($sshr) && type != ID($sshl) && type != ID($shr) && type != ID($shl) && type != ID($shift) && type != ID($shiftx) &&
359					type != ID($pos) && type != ID($buf) && type != ID($neg) && type != ID($not)) {
360				if (!signed1 || !signed2)
361					signed1 = false, signed2 = false;
362			}
363	
364	#define HANDLE_CELL_TYPE(_t) if (type == ID($##_t)) return const_ ## _t(arg1, arg2, signed1, signed2, result_len);
365			HANDLE_CELL_TYPE(not)
366			HANDLE_CELL_TYPE(and)
367			HANDLE_CELL_TYPE(or)
368			HANDLE_CELL_TYPE(xor)
369			HANDLE_CELL_TYPE(xnor)
370			HANDLE_CELL_TYPE(reduce_and)
371			HANDLE_CELL_TYPE(reduce_or)
372			HANDLE_CELL_TYPE(reduce_xor)
373			HANDLE_CELL_TYPE(reduce_xnor)
374			HANDLE_CELL_TYPE(reduce_bool)
375			HANDLE_CELL_TYPE(logic_not)
376			HANDLE_CELL_TYPE(logic_and)
377			HANDLE_CELL_TYPE(logic_or)
378			HANDLE_CELL_TYPE(shl)
379			HANDLE_CELL_TYPE(shr)
380			HANDLE_CELL_TYPE(sshl)
381			HANDLE_CELL_TYPE(sshr)
382			HANDLE_CELL_TYPE(shift)
383			HANDLE_CELL_TYPE(shiftx)
384			HANDLE_CELL_TYPE(lt)
385			HANDLE_CELL_TYPE(le)
386			HANDLE_CELL_TYPE(eq)
387			HANDLE_CELL_TYPE(ne)
388			HANDLE_CELL_TYPE(eqx)
389			HANDLE_CELL_TYPE(nex)
390			HANDLE_CELL_TYPE(ge)
391			HANDLE_CELL_TYPE(gt)
392			HANDLE_CELL_TYPE(add)
393			HANDLE_CELL_TYPE(sub)
394			HANDLE_CELL_TYPE(mul)
395			HANDLE_CELL_TYPE(div)
396			HANDLE_CELL_TYPE(mod)
397			HANDLE_CELL_TYPE(divfloor)
398			HANDLE_CELL_TYPE(modfloor)
399			HANDLE_CELL_TYPE(pow)
400			HANDLE_CELL_TYPE(pos)
401			HANDLE_CELL_TYPE(neg)
402	#undef HANDLE_CELL_TYPE
403	
404			if (type.in(ID($_BUF_), ID($buf)))
405				return arg1;
406			if (type == ID($_NOT_))
407				return eval_not(arg1);
408			if (type == ID($_AND_))
409				return const_and(arg1, arg2, false, false, 1);
410			if (type == ID($_NAND_))
411				return eval_not(const_and(arg1, arg2, false, false, 1));
412			if (type == ID($_OR_))
413				return const_or(arg1, arg2, false, false, 1);
414			if (type == ID($_NOR_))
415				return eval_not(const_or(arg1, arg2, false, false, 1));
416			if (type == ID($_XOR_))
417				return const_xor(arg1, arg2, false, false, 1);
418			if (type == ID($_XNOR_))
419				return const_xnor(arg1, arg2, false, false, 1);
420			if (type == ID($_ANDNOT_))
421				return const_and(arg1, eval_not(arg2), false, false, 1);
422			if (type == ID($_ORNOT_))
423				return const_or(arg1, eval_not(arg2), false, false, 1);
424	
425			if (errp != nullptr) {
426				*errp = true;
427				return State::Sm;
428			}
429	
430			log_abort();
431		}
