433		// Consider using the ConstEval struct instead if you need named ports and/or multiple outputs
434		static RTLIL::Const eval(RTLIL::Cell *cell, const RTLIL::Const &arg1, const RTLIL::Const &arg2, bool *errp = nullptr)
435		{
436			if (cell->type == ID($slice)) {
437				int width = cell->parameters.at(ID::Y_WIDTH).as_int();
438				int offset = cell->parameters.at(ID::OFFSET).as_int();
439				return arg1.extract(offset, width);
440			}
441	
442			if (cell->type == ID($concat)) {
443				RTLIL::Const ret = arg1;
444				ret.append(arg2);
445				return ret;
446			}
447	
448			if (cell->type == ID($bmux))
449			{
450				return const_bmux(arg1, arg2);
451			}
452	
453			if (cell->type == ID($demux))
454			{
455				return const_demux(arg1, arg2);
456			}
457	
458			if (cell->type == ID($bweqx))
459			{
460				return const_bweqx(arg1, arg2);
461			}
462	
463			if (cell->type == ID($lut))
464			{
465				int width = cell->parameters.at(ID::WIDTH).as_int();
466	
467				std::vector<RTLIL::State> t = cell->parameters.at(ID::LUT).to_bits();
468				while (GetSize(t) < (1 << width))
469					t.push_back(State::S0);
470				t.resize(1 << width);
471	
472				return const_bmux(t, arg1);
473			}
474	
475			if (cell->type == ID($sop))
476			{
477				int width = cell->parameters.at(ID::WIDTH).as_int();
478				int depth = cell->parameters.at(ID::DEPTH).as_int();
479				std::vector<RTLIL::State> t = cell->parameters.at(ID::TABLE).to_bits();
480	
481				while (GetSize(t) < width*depth*2)
482					t.push_back(State::S0);
483	
484				RTLIL::State default_ret = State::S0;
485	
486				for (int i = 0; i < depth; i++)
487				{
488					bool match = true;
489					bool match_x = true;
490	
491					for (int j = 0; j < width; j++) {
492						RTLIL::State a = arg1.at(j);
493						if (t.at(2*width*i + 2*j + 0) == State::S1) {
494							if (a == State::S1) match_x = false;
495							if (a != State::S0) match = false;
496						}
497						if (t.at(2*width*i + 2*j + 1) == State::S1) {
498							if (a == State::S0) match_x = false;
499							if (a != State::S1) match = false;
500						}
501					}
502	
503					if (match)
504						return State::S1;
505	
506					if (match_x)
507						default_ret = State::Sx;
508				}
509	
510				return default_ret;
511			}
512	
513			bool signed_a = cell->parameters.count(ID::A_SIGNED) > 0 && cell->parameters[ID::A_SIGNED].as_bool();
514			bool signed_b = cell->parameters.count(ID::B_SIGNED) > 0 && cell->parameters[ID::B_SIGNED].as_bool();
515			int result_len = cell->parameters.count(ID::Y_WIDTH) > 0 ? cell->parameters[ID::Y_WIDTH].as_int() : -1;
516			return eval(cell->type, arg1, arg2, signed_a, signed_b, result_len, errp);
517		}
518	
519		// Consider using the ConstEval struct instead if you need named ports and/or multiple outputs
520		static RTLIL::Const eval(RTLIL::Cell *cell, const RTLIL::Const &arg1, const RTLIL::Const &arg2, const RTLIL::Const &arg3, bool *errp = nullptr)
521		{
522			if (cell->type.in(ID($mux), ID($_MUX_)))
523				return const_mux(arg1, arg2, arg3);
524			if (cell->type == ID($_NMUX_))
525				return eval_not(const_mux(arg1, arg2, arg3));
526			if (cell->type == ID($bwmux))
527				return const_bwmux(arg1, arg2, arg3);
528			if (cell->type == ID($pmux))
529				return const_pmux(arg1, arg2, arg3);
530			if (cell->type == ID($_AOI3_))
531				return eval_not(const_or(const_and(arg1, arg2, false, false, 1), arg3, false, false, 1));
532			if (cell->type == ID($_OAI3_))
533				return eval_not(const_and(const_or(arg1, arg2, false, false, 1), arg3, false, false, 1));
534	
535			log_assert(arg3.size() == 0);
536			return eval(cell, arg1, arg2, errp);
537		}
538	
539		// Consider using the ConstEval struct instead if you need named ports and/or multiple outputs
540		static RTLIL::Const eval(RTLIL::Cell *cell, const RTLIL::Const &arg1, const RTLIL::Const &arg2, const RTLIL::Const &arg3, const RTLIL::Const &arg4, bool *errp = nullptr)
541		{
542			if (cell->type == ID($_AOI4_))
543				return eval_not(const_or(const_and(arg1, arg2, false, false, 1), const_and(arg3, arg4, false, false, 1), false, false, 1));
544			if (cell->type == ID($_OAI4_))
545				return eval_not(const_and(const_or(arg1, arg2, false, false, 1), const_or(arg3, arg4, false, false, 1), false, false, 1));
546	
547			log_assert(arg4.size() == 0);
548			return eval(cell, arg1, arg2, arg3, errp);
549		}
550	};
551	
552	YOSYS_NAMESPACE_END
553	
554	#endif
