444	struct Categories {
445		struct Category {
446			std::array<bool, MAX_CELLS> data{};
447			constexpr bool operator()(IdString type) const {
448				size_t idx = type.index_;
449				if (idx >= MAX_CELLS)
450					return false;
451				return data[idx];
452			}
453			constexpr bool operator[](size_t idx) {
454				return data[idx];
455			}
456			constexpr void set_id(IdString type, bool val = true) {
457				size_t idx = type.index_;
458				if (idx >= MAX_CELLS)
459					return; // TODO should be an assert but then it's not constexpr
460				data[idx] = val;
461			}
462			constexpr void set(size_t idx, bool val = true) {
463				data[idx] = val;
464			}
465			constexpr size_t size() const { return data.size(); }
466		};
467		Category empty {};
468		Category is_known {};
469		Category is_evaluable {};
470		Category is_combinatorial {};
471		Category is_synthesizable {};
472		Category is_stdcell {};
473		Category is_ff {};
474		Category is_mem_noff {};
475		Category is_anyinit {};
476		Category is_tristate {};
477		constexpr Categories() {
478			for (size_t i = 0; i < builder.count; ++i) {
479				auto& cell = builder.cells[i];
480				size_t idx = cell.type.index_;
481				is_known.set(idx);
482				is_evaluable.set(idx, cell.features.is_evaluable);
483				is_combinatorial.set(idx, cell.features.is_combinatorial);
484				is_synthesizable.set(idx, cell.features.is_synthesizable);
485				is_stdcell.set(idx, cell.features.is_stdcell);
486				is_ff.set(idx, cell.features.is_ff);
487				is_mem_noff.set(idx, cell.features.is_mem_noff);
488				is_anyinit.set(idx, cell.features.is_anyinit);
489				is_tristate.set(idx, cell.features.is_tristate);
490			}
491		}
492		constexpr static Category join(Category left, Category right) {
493			Category c {};
494			for (size_t i = 0; i < MAX_CELLS; ++i) {
495				c.set(i, left[i] || right[i]);
496			}
497			return c;
498		}
499		constexpr static Category meet(Category left, Category right) {
500			Category c {};
501			for (size_t i = 0; i < MAX_CELLS; ++i) {
502				c.set(i, left[i] && right[i]);
503			}
504			return c;
505		}
506		// Sketchy! Make sure to always meet with only the known universe.
507		// In other words, no modus tollens allowed
508		constexpr static Category complement(Category arg) {
509			Category c {};
510			for (size_t i = 0; i < MAX_CELLS; ++i) {
511				c.set(i, !arg[i]);
512			}
513			return c;
514		}
515	};
