568		NewCellTypes(RTLIL::Design *design) {
569			static_cell_types = StaticCellTypes::categories.empty;
570			setup(design);
571		}
572		void setup(RTLIL::Design *design = NULL) {
573			if (design)
574				setup_design(design);
575			static_cell_types = StaticCellTypes::categories.is_known;
576		}
577		void setup_design(RTLIL::Design *design) {
578			for (auto module : design->modules())
579				setup_module(module);
580		}
581	
582		void setup_module(RTLIL::Module *module) {
583			pool<RTLIL::IdString> inputs, outputs;
584			for (RTLIL::IdString wire_name : module->ports) {
585				RTLIL::Wire *wire = module->wire(wire_name);
586				if (wire->port_input)
587					inputs.insert(wire->name);
588				if (wire->port_output)
589					outputs.insert(wire->name);
590			}
591			setup_type(module->name, inputs, outputs);
592		}
593	
594		void setup_type(RTLIL::IdString type, const pool<RTLIL::IdString> &inputs, const pool<RTLIL::IdString> &outputs, bool is_evaluable = false, bool is_combinatorial = false, bool is_synthesizable = false) {
595			NewCellType ct = {type, inputs, outputs, is_evaluable, is_combinatorial, is_synthesizable};
596			custom_cell_types[ct.type] = ct;
597		}
598	
599		void clear() {
600			custom_cell_types.clear();
601			static_cell_types = StaticCellTypes::categories.empty;
602		}
603	
604		bool cell_known(const RTLIL::IdString &type) const {
605			return static_cell_types(type) || custom_cell_types.count(type) != 0;
606		}
607	
608		bool cell_output(const RTLIL::IdString &type, const RTLIL::IdString &port) const
609		{
610			if (static_cell_types(type) && StaticCellTypes::port_info.outputs(type).contains(port)) {
611				return true;
612			}
613			auto it = custom_cell_types.find(type);
614			return it != custom_cell_types.end() && it->second.outputs.count(port) != 0;
615		}
616	
617		bool cell_input(const RTLIL::IdString &type, const RTLIL::IdString &port) const
618		{
619			if (static_cell_types(type) && StaticCellTypes::port_info.inputs(type).contains(port)) {
620				return true;
621			}
622			auto it = custom_cell_types.find(type);
623			return it != custom_cell_types.end() && it->second.inputs.count(port) != 0;
624		}
625	
626		RTLIL::PortDir cell_port_dir(RTLIL::IdString type, RTLIL::IdString port) const
627		{
628			bool is_input, is_output;
629			if (static_cell_types(type)) {
630				is_input = StaticCellTypes::port_info.inputs(type).contains(port);
631				is_output = StaticCellTypes::port_info.outputs(type).contains(port);
632			} else {
633				auto it = custom_cell_types.find(type);
634				if (it == custom_cell_types.end())
635					return RTLIL::PD_UNKNOWN;
636				is_input = it->second.inputs.count(port);
637				is_output = it->second.outputs.count(port);
638			}
639			return RTLIL::PortDir(is_input + is_output * 2);
640		}
641		bool cell_evaluable(const RTLIL::IdString &type) const
642		{
643			return static_cell_types(type) && StaticCellTypes::categories.is_evaluable(type);
644		}
645	};
646	
647	extern NewCellTypes yosys_celltypes;
648	
649	YOSYS_NAMESPACE_END
650	
651	#endif
