static std::optional<int> parse_autoidx(std::string_view v)
{
	// autoidx values can never be <= 0, so there can never be a leading 0 digit.
	if (v.empty() || v[0] == '0')
		return std::nullopt;
	for (char ch : v) {
		if (ch < '0' || ch > '9')
			return std::nullopt;
	}
	int p_autoidx;
	if (std::from_chars(v.data(), v.data() + v.size(), p_autoidx).ec != std::errc())
		return std::nullopt;
	return p_autoidx;
}

